import web3
from web3 import exceptions as w3_exceptions
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    if 'signature' not in data or 'message' not in data:
        return jsonify({'error': 'Missing signature or message'}), 400
    
    try:
        w3 = web3.Web3(web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'))
        
        eth_account = web3.Account.recover(data['signature'], hashfunc='keccak', sigdecode='hex')
        
        address = eth_account.address
        
        if data['address'] != address:
            return jsonify({'error': 'Addresses do not match'}), 401
        
        # You can add additional logic here to validate the address against your database or other sources
        return jsonify({'status': 'success', 'address': address}), 200
    
    except w3_exceptions.SignatureError:
        return jsonify({'error': 'Invalid signature'}), 400

if __name__ == '__main__':
    app.run(debug=True)